{
  "name": "replicache-todo",
  "version": "0.2.0",
  "private": true,
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "format": "prettier --write './**/*.{js,jsx,json,ts,tsx,html,css,md}'"
  },
  "dependencies": {
    "classnames": "^2.3.1",
    "next": "^12.1.6",
    "react": "17.0.2",
    "react-dom": "17.0.2",
    "replicache": "^11.0.0",
    "replicache-nextjs": "^0.2.0",
    "replicache-react": "^2.7.0",
    "todomvc-app-css": "^2.4.2"
  },
  "devDependencies": {
    "@types/node": "^14.14.37",
    "@types/react": "^17.0.11",
    "prettier": "^2.2.1",
    "ts-node": "^10.7.0",
    "typescript": "^4.7.4"
  },
  "eslintConfig": {
    "ecmaFeatures": {
      "jsx": true,
      "modules": true
    },
    "env": {
      "browser": true,
      "node": true
    },
    "parser": "babel-eslint",
    "rules": {
      "quotes": [
        2,
        "single"
      ],
      "strict": [
        2,
        "never"
      ],
      "react/jsx-uses-react": 2,
      "react/jsx-uses-vars": 2,
      "react/react-in-jsx-scope": 2
    },
    "plugins": [
      "react"
    ]
  },
  "prettier": {
    "singleQuote": false,
    "trailingComma": "es5",
    "arrowParens": "always",
    "bracketSpacing": true,
    "tabWidth": 2,
    "useTabs": false
  }
}

import React from "react";
import TodoTextInput from "./todo-text-input";

const Header = ({ onNewItem }: { onNewItem: (text: string) => void }) => (
  <header className="header">
    <h1>todos</h1>
    <TodoTextInput
      initial=""
      placeholder="What needs to be done?"
      onSubmit={onNewItem}
    />
  </header>
);

export default Header;
